<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  body {
    background-color: #121212;
    color: #e0e0e0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    margin: 0;
  }

  h1 { margin-bottom: 20px; font-weight: 300; letter-spacing: 1px; }

  #sand-container {
    position: relative;
    box-shadow: 0 10px 30px rgba(0,0,0,0.5);
    border-radius: 4px;
    overflow: hidden;
    background-color: #000;
  }

  canvas {
    display: block;
    width: 400px;
    height: 400px;
    image-rendering: pixelated; /* Crisp pixels */
    cursor: crosshair;
  }

  .controls {
    margin-top: 20px;
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    justify-content: center;
  }

  button {
    padding: 10px 20px;
    border: none;
    border-radius: 4px;
    font-size: 14px;
    font-weight: 500;
    cursor: pointer;
    transition: transform 0.1s, opacity 0.2s;
    background-color: #333;
    color: #fff;
    box-shadow: 0 2px 5px rgba(0,0,0,0.3);
  }

  button:hover { opacity: 0.9; transform: translateY(-1px); }
  button:active { transform: translateY(1px); }

  .mat-btn {
    display: flex;
    align-items: center;
    gap: 8px;
    background-color: #2c3e50;
  }

  .color-indicator {
    width: 16px;
    height: 16px;
    border-radius: 50%;
    display: inline-block;
  }

  /* Material Colors */
  .color-sand { background-color: #f4d35e; }
  .color-water { background-color: #3498db; }
  .color-wall { background-color: #7f8c8d; }
  .color-acid { background-color: #2ecc71; }
  .color-empty { background-color: transparent; border: 1px solid #555; }

  /* Active State */
  button.active {
    outline: 3px solid rgba(255,255,255,0.3);
    box-shadow: 0 0 10px rgba(255,255,255,0.2);
  }

  #clear {
    background-color: #c0392b;
    margin-left: 20px;
  }
</style>
</head>
<body>

<h1>Falling Sand Sandbox</h1>

<div id="sand-container">
  <canvas id="sand" width="100" height="100"></canvas>
</div>

<div class="controls">
  <button id="mat-sand" class="mat-btn active" data-mat="sand"><span class="color-indicator color-sand mat-indicator"></span>Sand</button>
  <button id="mat-water" class="mat-btn" data-mat="water"><span class="color-indicator color-water mat-indicator"></span>Water</button>
  <button id="mat-wall" class="mat-btn" data-mat="wall"><span class="color-indicator color-wall mat-indicator"></span>Wall</button>
  <button id="mat-acid" class="mat-btn" data-mat="acid"><span class="color-indicator color-acid mat-indicator"></span>Acid</button>
  <button id="mat-empty" class="mat-btn" data-mat="empty"><span class="color-indicator color-empty mat-indicator"></span>Eraser</button>

  <button id="clear">Clear Grid</button>
</div>

<script>
(function() {
  // --- Configuration ---
  const W = 100;
  const H = 100;

  // Material IDs
  const EMPTY = 0;
  const SAND = 1;
  const WATER = 2;
  const WALL = 3;
  const ACID = 4;

  // --- State ---
  let grid = new Uint8Array(W * H);
  let currentMat = SAND;
  let isMouseDown = false;

  // Canvas & Context
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d', { alpha: false });

  // --- API Object ---
  window.sim = {
    w: W,
    h: H,

    get(x, y) {
      if (x < 0 || x >= W || y < 0 || y >= H) return "wall"; // Boundaries act as solid walls
      return materialName(grid[y * W + x]);
    },

    set(x, y, material) {
      if (x < 0 || x >= W || y < 0 || y >= H) return;
      grid[y * W + x] = materialId(material);
    },

    clear() {
      grid.fill(EMPTY);
    },

    tick(n) {
      for (let i = 0; i < n; i++) {
        step();
      }
    }
  };

  // --- Helpers ---
  function materialName(id) {
    switch(id) {
      case EMPTY: return "empty";
      case SAND: return "sand";
      case WATER: return "water";
      case WALL: return "wall";
      case ACID: return "acid";
      default: return "unknown";
    }
  }

  function materialId(name) {
    switch(name) {
      case "empty": return EMPTY;
      case "sand": return SAND;
      case "water": return WATER;
      case "wall": return WALL;
      case "acid": return ACID;
      default: return EMPTY;
    }
  }

  function draw() {
    // Clear background (though we fill with empty usually)
    ctx.fillStyle = '#000';
    ctx.fillRect(0, 0, W, H);

    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const id = grid[y * W + x];
        if (id === EMPTY) continue;

        let color;
        switch(id) {
          case SAND: color = '#f4d35e'; break;
          case WATER: color = '#3498db'; break;
          case WALL: color = '#7f8c8d'; break;
          case ACID: color = '#2ecc71'; break;
          default: color = '#fff';
        }

        ctx.fillStyle = color;
        // Draw rect at x, y with size 1x1 (since canvas is 100x100)
        // CSS scales the CANVAS element up to 400px.
        ctx.fillRect(x, y, 1, 1);
      }
    }
  }

  function step() {
    // Process bottom-up to prevent teleporting
    for (let y = H - 2; y >= 0; y--) {
      for (let x = 0; x < W; x++) {
        const idx = y * W + x;
        const type = grid[idx];

        if (type === EMPTY || type === WALL) continue;

        // Try to move down
        const belowIdx = (y + 1) * W + x;
        const belowType = grid[belowIdx];

        if (type === SAND) {
          if (belowType === EMPTY) {
            grid[idx] = EMPTY;
            grid[belowIdx] = SAND;
          } else if (belowType === WATER || belowType === ACID) {
            // Swap: Sand sinks
            grid[idx] = belowType;
            grid[belowIdx] = SAND;
          } else if (belowType === WALL) {
            // Blocked, try diagonal
            const dir = Math.random() < 0.5 ? -1 : 1;

            // Check Left-Down then Right-Down based on random start
            const checks = [
              { dx: -1, dy: 1 }, 
              { dx: 1, dy: 1 }
            ];
            if (dir === 1) checks.reverse();

            for (const {dx, dy} of checks) {
              const nx = x + dx;
              const ny = y + dy;
              if (nx >= 0 && nx < W && ny < H) {
                if (grid[ny * W + nx] === EMPTY) {
                  grid[idx] = EMPTY;
                  grid[ny * W + nx] = SAND;
                  break;
                }
              }
            }
          }
        } 
        else if (type === WATER || type === ACID) {
          // Acid moves like water, but dissolves targets.

          // Check Below
          let targetIdx = belowIdx;
          let targetType = belowType;

          if (targetType === EMPTY) {
            grid[idx] = EMPTY;
            grid[targetIdx] = type;
          } else if (targetType === WALL || targetType === SAND) {
             // Dissolve! Both disappear.
             grid[idx] = EMPTY;
             grid[targetIdx] = EMPTY;
          } else if (targetType === WATER || targetType === ACID) {
            // Blocked by liquid. Try spreading sideways.
            const checks = [
              { dx: -1, dy: 0 }, 
              { dx: 1, dy: 0 }
            ];
            // Randomize order
            if (Math.random() < 0.5) checks.reverse();

            let moved = false;
            for (const {dx, dy} of checks) {
              const nx = x + dx;
              const ny = y + dy;
              if (nx >= 0 && nx < W && ny < H) {
                const nIdx = ny * W + nx;
                const nType = grid[nIdx];

                // Acid eats Wall/Sand on contact during spread too? 
                // Prompt: "dissolves sand or wall cells it touches below or beside"
                if (type === ACID && (nType === WALL || nType === SAND)) {
                   grid[idx] = EMPTY;
                   grid[nIdx] = EMPTY;
                   moved = true;
                   break;
                } else if (nType === EMPTY) {
                   grid[idx] = EMPTY;
                   grid[nIdx] = type;
                   moved = true;
                   break;
                }
              }
            }
          }
        }
      }
    }
  }

  // --- Animation Loop ---
  let lastTime = 0;
  function loop(timestamp) {
    if (!lastTime) lastTime = timestamp;
    const delta = timestamp - lastTime;

    // Run at approx 60 FPS (16ms per frame)
    if (delta > 16) {
      step();
      draw();
      lastTime = timestamp;
    }
    requestAnimationFrame(loop);
  }

  // Start loop
  requestAnimationFrame(loop);


  // --- UI Interaction ---

  // Material Selection
  const buttons = document.querySelectorAll('.mat-btn');
  buttons.forEach(btn => {
    btn.addEventListener('click', () => {
      buttons.forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      currentMat = btn.dataset.mat;
    });
  });

  // Clear Button
  document.getElementById('clear').addEventListener('click', () => {
    window.sim.clear();
    draw();
  });

  // Mouse Painting
  const container = document.getElementById('sand-container');

  function getMousePos(e) {
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((e.clientX - rect.left) / (rect.width / W));
    const y = Math.floor((e.clientY - rect.top) / (rect.height / H));
    return { x, y };
  }

  function paint(e) {
    if (!isMouseDown) return;
    const pos = getMousePos(e);

    const matId = materialId(currentMat);
    const r = 1; // Brush radius

    for (let dy = -r; dy <= r; dy++) {
      for (let dx = -r; dx <= r; dx++) {
        const nx = pos.x + dx;
        const ny = pos.y + dy;
        if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
          grid[ny * W + nx] = matId;
        }
      }
    }
  }

  canvas.addEventListener('mousedown', (e) => {
    isMouseDown = true;
    paint(e);
  });

  window.addEventListener('mouseup', () => {
    isMouseDown = false;
  });

  canvas.addEventListener('mousemove', (e) => {
    if (isMouseDown) paint(e);
  });

  // Prevent context menu on right click
  canvas.addEventListener('contextmenu', e => e.preventDefault());

})();
</script>
</body>
</html>
